import { DefaultTheme, NavigationContainer } from '@react-navigation/native';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { FirstAccess, Login } from '@semparar/mf-app-user';
import * as React from 'react';
import { View } from 'react-native';

import AdditionalCardAge from '../screens/AdditionalCard/AdditionalCardAge';
import AdditionalCardConcluded from '../screens/AdditionalCard/AdditionalCardConcluded';
import AdditionalCardInstructions from '../screens/AdditionalCard/AdditionalCardInstructions';
import AdditionalCardName from '../screens/AdditionalCard/AdditionalCardName';
import CheckoutAdditionalCard from '../screens/AdditionalCard/CheckoutAdditionalCard';
import EditAddressAdditionalCard from '../screens/AdditionalCard/EditAddressAdditionalCard';
import LimitAdditionalCard from '../screens/AdditionalCard/LimitAdditionalCard';
import AddressEditCard from '../screens/AddressEditCard';
import BenefitsScreen from '../screens/Benefits';
import DetailPhysicalCard from '../screens/Cards/DetailPhysicalCard';
import AuxiliaryScreen from '../screens/Cards/DetailPhysicalCard/AuxiliaryScreen';
import BlockDuplicateModal from '../screens/Cards/DetailPhysicalCard/Modal';
import DetailTagCard from '../screens/Cards/DetailTagCard';
import DetailVirtualCardRecurrent from '../screens/Cards/DetailVirtualCardRecurrent';
import CardTracking from '../screens/CardTracking';
import EditAddressTrackingCard from '../screens/CardTracking/EditAddressTrackingCard';
import MissingInstructions from '../screens/CardTracking/MissingInstructions';
import CardUnlock from '../screens/CardUnlock';
import CardValidation from '../screens/CardValidation';
import CardVerificationCode from '../screens/CardVerificationCode';
import Cashback from '../screens/Cashback';
import SearchCashback from '../screens/Cashback/Search';
import Configurations from '../screens/Configurations';
import EditCardAddress from '../screens/EditCardAddress';
import Example from '../screens/Example/index';
import FaqExemptionEligibility from '../screens/FaqExemptionEligibility';
import FintechHome from '../screens/FintechHome';
import SearchActivity from '../screens/FintechHome/Search';
import InstructionsToCreatePassword from '../screens/InstructionsToCreatePassword';
import InstructionsToLiveness from '../screens/InstructionsToLiveness';
import InvoiceCard from '../screens/InvoiceCard';
import InvoiceCardDetails from '../screens/InvoiceCard/Details';
import InvoiceCashbackOnboarding from '../screens/InvoiceCashbackOnboarding';
import InvoiceCashbackPoints from '../screens/InvoiceCashbackPoints';
import InvoiceCashbackSummary from '../screens/InvoiceCashbackSummary';
import InvoicesHistory from '../screens/InvoicesHistory';
import Liveness from '../screens/Liveness';
import PasswordCard from '../screens/PasswordCard';
import ConfirmPasswordCard from '../screens/PasswordCard/ConfirmPasswordCard';
import PayInvoice from '../screens/PayInvoice/Options';
import SimulationResume from '../screens/PayInvoice/SimulationResume';
import PayMethods from '../screens/PayMethods';
import BankDetailsForm from '../screens/PayMethods/Backdrops/BankDetailsForm';
import PaymentChange from '../screens/PayMethods/Backdrops/PaymentChange';
import Points from '../screens/Points';
import PointsExtract from '../screens/PointsExtract';
import RewardProgramMarketplace from '../screens/RewardProgramMarketplace';
import AirlineMilesMarketplace from '../screens/AirlineMilesMarketplace';
import PointsDetail from '../screens/PointsDetail';
import Splash from '../screens/Splash';
import { PropsFintechCardRoutes } from './Models';
import { navigatorRef } from './navigation';
import LearnMoreRewardProgram from '../screens/LearnMoreRewardProgram';
const Stack = createNativeStackNavigator<PropsFintechCardRoutes>();

const MainTheme = {
  ...DefaultTheme,
  colors: {
    ...DefaultTheme.colors,
  },
};

export const FintechCardPlaceRoutes = (
  <>
    <Stack.Screen name="EditAddressAdditionalCard" component={EditAddressAdditionalCard} />
    <Stack.Screen name="LimitAdditionalCard" component={LimitAdditionalCard} />
    <Stack.Screen name="CheckoutAdditionalCard" component={CheckoutAdditionalCard} />
    <Stack.Screen name="PayInvoice" component={PayInvoice} />
    <Stack.Screen name="RewardProgramMarketplace" component={RewardProgramMarketplace} />
    <Stack.Screen name="AirlineMilesMarketplace" component={AirlineMilesMarketplace} />
    <Stack.Screen name="Cashback" component={Cashback} />
    <Stack.Screen name="RewardProgram" component={Points} />
    <Stack.Screen name="LearnMoreRewardProgram" component={LearnMoreRewardProgram} />
    <Stack.Screen name="PointsExtract" component={PointsExtract} />
    <Stack.Screen name="PointsDetail" component={PointsDetail} />
    <Stack.Screen name="InvoiceCashbackOnboarding" component={InvoiceCashbackOnboarding} />
    <Stack.Screen name="InvoiceCashbackPoints" component={InvoiceCashbackPoints} />
    <Stack.Screen name="InvoiceCashbackSummary" component={InvoiceCashbackSummary} />
    <Stack.Screen name="SearchCashback" component={SearchCashback} />
    <Stack.Screen name="SearchActivity" component={SearchActivity} />
    <Stack.Screen name="CardUnlock" component={CardUnlock} />
    <Stack.Screen name="CardVerificationCode" component={CardVerificationCode} />
    <Stack.Screen name="PasswordCard" component={PasswordCard} />
    <Stack.Screen name="ConfirmPasswordCard" component={ConfirmPasswordCard} />
    <Stack.Screen name="AdditionalCardAge" component={AdditionalCardAge} />
    <Stack.Screen name="DetailPhysicalCard" component={DetailPhysicalCard} />
    <Stack.Screen name="BlockDuplicateModal" component={BlockDuplicateModal} />
    <Stack.Screen name="AuxiliaryScreen" component={AuxiliaryScreen} />
    <Stack.Screen name="EditCardAddressHome" component={EditCardAddress} />
    <Stack.Screen name="MissingInstructions" component={MissingInstructions} />
    <Stack.Screen name="CardTracking" component={CardTracking} />
    <Stack.Screen name="InvoiceCard" component={InvoiceCard} />
    <Stack.Screen name="InvoicesHistory" component={InvoicesHistory} />
    <Stack.Screen name="Configurations" component={Configurations} />
    <Stack.Screen name="DetailVirtualCardRecurrent" component={DetailVirtualCardRecurrent} />
    <Stack.Screen name="SimulationResume" component={SimulationResume} />
    <Stack.Screen name="InstructionsToLiveness" component={InstructionsToLiveness} />
    <Stack.Screen name="Liveness" component={Liveness} />
    <Stack.Screen name="InstructionsToCreatePassword" component={InstructionsToCreatePassword} />
    <Stack.Screen name="TagDetail" component={DetailTagCard} />
    <Stack.Screen name="FintechBenefits" component={BenefitsScreen} />
    <Stack.Screen name="FaqExemptionEligibility" component={FaqExemptionEligibility} />
    <Stack.Screen name="InvoiceCardDetails" component={InvoiceCardDetails} />

    <Stack.Screen name="PayMethods" component={PayMethods} />
    <Stack.Screen name="PaymentChange" component={PaymentChange} />
    <Stack.Screen name="BankDetailsForm" component={BankDetailsForm} />
    <Stack.Screen name="EditAddressTrackingCard" component={EditAddressTrackingCard} />
    <Stack.Screen name="AdditionalCardInstructions" component={AdditionalCardInstructions} />
    <Stack.Screen name="AdditionalCardConcluded" component={AdditionalCardConcluded} />
    <Stack.Screen name="AdditionalCardName" component={AdditionalCardName} />

    {/* EditAddressTrackingCard */}
    <Stack.Screen name="AddressEditCard" component={AddressEditCard} />
    <Stack.Screen name="CardValidation" component={CardValidation} />
  </>
);

const RouteStacks = (
  <Stack.Navigator
    initialRouteName="Splash"
    screenOptions={{
      headerShown: false,
    }}
  >
    <Stack.Screen name="FintechHome" component={FintechHome} />
    <Stack.Screen name="Splash" component={Splash} />
    <Stack.Screen name="LoginScreen" component={Login} />
    <Stack.Screen name="FirstAccess" component={FirstAccess} />
    <Stack.Screen name="Example" component={FintechHome} />
    <Stack.Screen name="Home" component={FintechHome} />
    <Stack.Screen name="HomeScreen" component={Example} />
    <Stack.Screen name="PlanDetails" component={Example} />
    <Stack.Screen name="Refuel" component={Example} />

    {FintechCardPlaceRoutes}
  </Stack.Navigator>
);

const Routes = () => {
  return (
    <View style={{ flex: 1 }}>
      <NavigationContainer theme={MainTheme} ref={navigatorRef}>
        {RouteStacks || null}
      </NavigationContainer>
    </View>
  );
};

export default Routes;

